　　整合mail发送邮件，其实就是通过代码来操作发送邮件的步骤，编辑收件人、邮件内容、邮件附件等等。通过邮件可以拓展出短信验证码、消息通知等业务。
一、pom文件引入依赖&lt;dependency&gt;    &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;    &lt;artifactId&gt;spring-boot-starter-mail&lt;/artifactId&gt;&lt;/dependency&gt;&lt;!--freemarker模板引擎是为了后面发送模板邮件 不需要的可以不引入--&gt;&lt;dependency&gt;    &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;    &lt;artifactId&gt;spring-boot-starter-freemarker&lt;/artifactId&gt;&lt;/dependency&gt;
二、application.yml文件中配置spring:  mail:    host: smtp.qq.xyz #这里换成自己的邮箱类型 例如qq邮箱就写smtp.qq.com    username: xx@qq.com #QQ邮箱    password: xxxxxxxxxxx #邮箱密码或者授权码    protocol: smtp #发送邮件协议    properties.mail.smtp.auth: true    properties.mail.smtp.port: 465 #端口号465或587    properties.mail.smtp.starttls.enable: true    properties.mail.smtp.starttls.required: true    properties.mail.smtp.ssl.enable: true #开启SSL    default-encoding: utf-8freemarker:  cache: false # 缓存配置 开发阶段应该配置为false 因为经常会改  suffix: .html # 模版后缀名 默认为ftl  charset: UTF-8 # 文件编码  template-loader-path: classpath:/templates/  # 存放模板的文件夹，以resource文件夹为相对路径
邮箱密码暴露在配置文件很不安全，一般都是采取授权码的形式。点开邮箱，然后在账户栏里面点击生成授权码：
三、编写MailUtils工具类@Component@Slf4jpublic class MailUtils&#123;    /**     * Spring官方提供的集成邮件服务的实现类，目前是Java后端发送邮件和集成邮件服务的主流工具。     */    @Resource    private JavaMailSender mailSender;    /**     * 从配置文件中注入发件人的姓名     */    @Value(&quot;$&#123;spring.mail.username&#125;&quot;)    private String fromEmail;    @Autowired    private FreeMarkerConfigurer freeMarkerConfigurer;    /**     * 发送文本邮件     * @param to      收件人     * @param subject 标题     * @param content 正文     */    public void sendSimpleMail(String to, String subject, String content) &#123;        SimpleMailMessage message = new SimpleMailMessage();        //发件人        message.setFrom(fromEmail);        message.setTo(to);        message.setSubject(subject);        message.setText(content);        mailSender.send(message);    &#125;    /**     * 发送html邮件     */    public void sendHtmlMail(String to, String subject, String content) &#123;        try &#123;            //注意这里使用的是MimeMessage            MimeMessage message = mailSender.createMimeMessage();            MimeMessageHelper helper = new MimeMessageHelper(message, true);            helper.setFrom(fromEmail);            helper.setTo(to);            helper.setSubject(subject);            //第二个参数：格式是否为html            helper.setText(content, true);            mailSender.send(message);        &#125;catch (MessagingException e)&#123;            log.error(&quot;发送邮件时发生异常！&quot;, e);        &#125;    &#125;    /**     * 发送模板邮件     * @param to     * @param subject     * @param template     */    public void sendTemplateMail(String to, String subject, String template)&#123;        try &#123;            // 获得模板            Template template1 = freeMarkerConfigurer.getConfiguration().getTemplate(template);            // 使用Map作为数据模型，定义属性和值            Map&lt;String,Object&gt; model = new HashMap&lt;&gt;();            model.put(&quot;myname&quot;,&quot;Ray。&quot;);            // 传入数据模型到模板，替代模板中的占位符，并将模板转化为html字符串            String templateHtml = FreeMarkerTemplateUtils.processTemplateIntoString(template1,model);            // 该方法本质上还是发送html邮件，调用之前发送html邮件的方法            this.sendHtmlMail(to, subject, templateHtml);        &#125; catch (TemplateException e) &#123;            log.error(&quot;发送邮件时发生异常！&quot;, e);        &#125; catch (IOException e) &#123;            log.error(&quot;发送邮件时发生异常！&quot;, e);        &#125;    &#125;    /**     * 发送带附件的邮件     * @param to     * @param subject     * @param content     * @param filePath     */    public void sendAttachmentsMail(String to, String subject, String content, String filePath) &#123;        try &#123;            MimeMessage message = mailSender.createMimeMessage();            //要带附件第二个参数设为true            MimeMessageHelper helper = new MimeMessageHelper(message, true);            helper.setFrom(fromEmail);            helper.setTo(to);            helper.setSubject(subject);            helper.setText(content, true);            FileSystemResource file = new FileSystemResource(new File(filePath));            String fileName = filePath.substring(filePath.lastIndexOf(File.separator));            helper.addAttachment(fileName, file);            mailSender.send(message);        &#125;catch (MessagingException e)&#123;            log.error(&quot;发送邮件时发生异常！&quot;, e);        &#125;    &#125;&#125;
MailUtils其实就是进一步封装Mail提供的JavaMailSender类，根据业务场景可以在工具类里面添加对应的方法，这里提供了发送文本邮件、html邮件、模板邮件、附件邮件的方法。
四、Controller层的实现@Api(tags = &quot;邮件管理&quot;)@RestController@RequestMapping(&quot;/mail&quot;)public class MailController &#123;    @Autowired    private MailUtils mailUtils;    /**     * 发送注册验证码     * @return 验证码     * @throws Exception     */    @ApiOperation(&quot;发送注册验证码&quot;)    @GetMapping(&quot;/test&quot;)    public String send()&#123;        mailUtils.sendSimpleMail(&quot;ruiyeclub@foxmail.com&quot;,&quot;普通文本邮件&quot;,&quot;普通文本邮件内容&quot;);        return &quot;OK&quot;;    &#125;    /**     * 发送注册验证码     * @return 验证码     * @throws Exception     */    @ApiOperation(&quot;发送注册验证码&quot;)    @PostMapping(&quot;/sendHtml&quot;)    public String sendTemplateMail()&#123;        mailUtils.sendHtmlMail(&quot;ruiyeclub@foxmail.com&quot;,&quot;一封html测试邮件&quot;,                &quot;&lt;div style=\&quot;text-align: center;position: absolute;\&quot; &gt;\n&quot;                        +&quot;&lt;h3&gt;\&quot;一封html测试邮件\&quot;&lt;/h3&gt;\n&quot;                        + &quot;&lt;div&gt;一封html测试邮件&lt;/div&gt;\n&quot;                        + &quot;&lt;/div&gt;&quot;);        return &quot;OK&quot;;    &#125;    @ApiOperation(&quot;发送html模板邮件&quot;)    @PostMapping(&quot;/sendTemplate&quot;)    public String sendTemplate()&#123;        mailUtils.sendTemplateMail(&quot;ruiyeclub@foxmail.com&quot;, &quot;基于模板的html邮件&quot;, &quot;hello.html&quot;);        return &quot;OK&quot;;    &#125;    @ApiOperation(&quot;发送带附件的邮件&quot;)    @GetMapping(&quot;sendAttachmentsMail&quot;)    public String sendAttachmentsMail()&#123;        String filePath = &quot;D:\\projects\\springboot\\template.png&quot;;        mailUtils.sendAttachmentsMail(&quot;xxxx@xx.com&quot;, &quot;带附件的邮件&quot;, &quot;邮件中有附件&quot;, filePath);        return &quot;OK&quot;;    &#125;&#125;
