　　前后端分离的项目，接口文档的存在十分重要。与手动编写接口文档不同，swagger是一个自动生成接口文档的工具，在需求不断变更的开发环境下，手动编写文档的效率实在太低。与新版的swagger3相比swagger2配置更少，使用更加方便。
一、pom文件中引入Swagger3依赖&lt;dependency&gt;     &lt;groupId&gt;io.springfox&lt;/groupId&gt;      &lt;artifactId&gt;springfox-boot-starter&lt;/artifactId&gt;      &lt;version&gt;3.0.0&lt;/version&gt;&lt;/dependency&gt;

二、Application上面加入@EnableOpenApi注解@EnableOpenApi@SpringBootApplication@MapperScan(basePackages = &#123;&quot;cn.ruiyeclub.dao&quot;&#125;)public class Swagger3Application &#123;    public static void main(String[] args) &#123;        SpringApplication.run(Swagger3Application.class, args);    &#125;&#125;

三、Swagger3Config的配置@Configurationpublic class Swagger3Config &#123;    @Bean    public Docket createRestApi() &#123;        return new Docket(DocumentationType.OAS_30)                .apiInfo(apiInfo())                .select()                .apis(RequestHandlerSelectors.withMethodAnnotation(ApiOperation.class))                .paths(PathSelectors.any())                .build();    &#125;    private ApiInfo apiInfo() &#123;        return new ApiInfoBuilder()                .title(&quot;Swagger3接口文档&quot;)                .description(&quot;更多请咨询服务开发者Ray。&quot;)                .contact(new Contact(&quot;Ray。&quot;, &quot;http://www.ruiyeclub.cn&quot;, &quot;ruiyeclub@foxmail.com&quot;))                .version(&quot;1.0&quot;)                .build();    &#125;&#125;

四、Swagger注解的使用说明@Api：用在请求的类上，表示对类的说明    tags=&quot;说明该类的作用，可以在UI界面上看到的注解&quot;    value=&quot;该参数没什么意义，在UI界面上也看到，所以不需要配置&quot;@ApiOperation：用在请求的方法上，说明方法的用途、作用    value=&quot;说明方法的用途、作用&quot;    notes=&quot;方法的备注说明&quot;@ApiImplicitParams：用在请求的方法上，表示一组参数说明    @ApiImplicitParam：用在@ApiImplicitParams注解中，指定一个请求参数的各个方面        name：参数名        value：参数的汉字说明、解释        required：参数是否必须传        paramType：参数放在哪个地方            · header --&gt; 请求参数的获取：@RequestHeader            · query --&gt; 请求参数的获取：@RequestParam            · path（用于restful接口）--&gt; 请求参数的获取：@PathVariable            · body（不常用）            · form（不常用）            dataType：参数类型，默认String，其它值dataType=&quot;Integer&quot;               defaultValue：参数的默认值@ApiResponses：用在请求的方法上，表示一组响应    @ApiResponse：用在@ApiResponses中，一般用于表达一个错误的响应信息        code：数字，例如400        message：信息，例如&quot;请求参数没填好&quot;        response：抛出异常的类@ApiModel：用于响应类上，表示一个返回响应数据的信息            （这种一般用在post创建的时候，使用@RequestBody这样的场景，            请求参数无法使用@ApiImplicitParam注解进行描述的时候）    @ApiModelProperty：用在属性上，描述响应类的属性
Controller层的配置：
@Api(tags = &quot;用户信息管理&quot;)@RestController@RequestMapping(&quot;userRecord&quot;)public class UserRecordController extends ApiController &#123;    /**     * 服务对象     */    @Resource    private UserRecordService userRecordService;    /**     * 分页查询所有数据     * @param page       分页对象     * @param userRecord 查询实体     * @return 所有数据     */    @ApiOperation(&quot;分页查询所有数据&quot;)    @GetMapping(&quot;page&quot;)    public R selectAll(Page&lt;UserRecord&gt; page, UserRecord userRecord) &#123;        return success(this.userRecordService.page(page, new QueryWrapper&lt;&gt;(userRecord)));    &#125;    /**     * 通过主键查询单条数据     * @param id 主键     * @return 单条数据     */    @ApiOperation(&quot;通过主键查询单条数据&quot;)    @GetMapping(&quot;&#123;id&#125;&quot;)    public R selectOne(@PathVariable Serializable id) &#123;        return success(this.userRecordService.getById(id));    &#125;    /**     * 新增数据     * @param userRecord 实体对象     * @return 新增结果     */    @ApiOperation(&quot;新增数据&quot;)    @PostMapping(&quot;insert&quot;)    public R insert(@RequestBody UserRecord userRecord) &#123;        return success(this.userRecordService.save(userRecord));    &#125;    /**     * 修改数据     * @param userRecord 实体对象     * @return 修改结果     */    @ApiOperation(&quot;修改数据&quot;)    @PutMapping(&quot;update&quot;)    public R update(@RequestBody UserRecord userRecord) &#123;        return success(this.userRecordService.updateById(userRecord));    &#125;    /**     * 删除数据     * @param idList 主键结合     * @return 删除结果     */    @ApiOperation(&quot;删除数据&quot;)    @DeleteMapping(&quot;delete&quot;)    public R delete(@RequestParam(&quot;idList&quot;) List&lt;Long&gt; idList) &#123;        return success(this.userRecordService.removeByIds(idList));    &#125;&#125;

